// Prepare scraping configuration
const body = $json["body"] || {};

// Validate required fields
if (!body.targetUrl) {
  throw new Error('targetUrl is required');
}

return [{ json: {
  targetUrl: body.targetUrl,
  scrapeType: body.scrapeType || 'property_listing', // property_listing, mortgage_rates, school_ratings, rental_comps, mls_listing, government_records
  selectors: body.selectors || {},
  formData: body.formData || {},
  action: body.action || 'scrape', // scrape, fill_form, submit_form
  outputFormat: body.outputFormat || 'json', // json, csv, html
  metadata: body.metadata || {},
  headers: body.headers || { "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36" }
} }];

// Perform web scraping or form operations
const axios = require('axios');
const cheerio = require('cheerio');
const { parse } = require('json2csv');

const { targetUrl, scrapeType, selectors, formData, action, outputFormat, metadata, headers } = $json;

try {
  let results = {};
  let rawHtml = '';

  // Set default headers
  const requestHeaders = {
    'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/91.0.4472.124 Safari/537.36',
    'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,image/webp,*/*;q=0.8',
    'Accept-Language': 'en-US,en;q=0.5',
    'Accept-Encoding': 'gzip, deflate',
    'Connection': 'keep-alive',
    ...headers
  };

  if (action === 'scrape' || action === 'extract') {
    // Scraping logic
    const response = await axios.get(targetUrl, { headers: requestHeaders });
    rawHtml = response.data;
    const $ = cheerio.load(rawHtml);

    // Extract data based on selectors
    Object.keys(selectors).forEach(key => {
      const element = $(selectors[key]);
      if (element.length > 0) {
        // Handle multiple elements
        if (element.length > 1) {
          results[key] = element.map((i, el) => $(el).text().trim()).get();
        } else {
          results[key] = element.first().text().trim();
        }
      } else {
        results[key] = null;
      }
    });

    // Add scrape-type specific processing
    switch (scrapeType) {
      case 'property_listing':
        // Extract structured property data
        results.price = results.price || $('[class*="price"], [id*="price"]').first().text().replace(/[^\d]/g, '') || null;
        results.beds = results.beds || $('[class*="bed"], [id*="bed"]').first().text().match(/\d+/)?.[0] || null;
        results.baths = results.baths || $('[class*="bath"], [id*="bath"]').first().text().match(/\d+/)?.[0] || null;
        results.sqft = results.sqft || $('[class*="sqft"], [id*="sqft"], [class*="square"]').first().text().replace(/[^\d]/g, '') || null;
        results.address = results.address || $('[class*="address"], [id*="address"]').first().text().trim() || null;
        break;

      case 'mortgage_rates':
        // Extract mortgage rate data
        results.rate30yr = results.rate30yr || $('[class*="30-year"], [class*="30yr"]').first().text().replace(/[^\d.]/g, '') || null;
        results.rate15yr = results.rate15yr || $('[class*="15-year"], [class*="15yr"]').first().text().replace(/[^\d.]/g, '') || null;
        break;

      case 'school_ratings':
        // Extract school data
        results.schoolName = results.schoolName || $('[class*="school-name"], [class*="institution"]').first().text().trim() || null;
        results.rating = results.rating || $('[class*="rating"], [class*="score"]').first().text().replace(/[^\d.]/g, '') || null;
        break;

      case 'rental_comps':
        // Extract rental comparison data
        results.rent = results.rent || $('[class*="rent"], [class*="price"]').first().text().replace(/[^\d]/g, '') || null;
        results.bedrooms = results.bedrooms || $('[class*="bed"], [class*="br"]').first().text().match(/\d+/)?.[0] || null;
        break;
    }

    // Format output
    let outputData = results;
    if (outputFormat === 'csv' && typeof results === 'object' && !(results instanceof Array)) {
      try {
        outputData = parse([results]);
      } catch (e) {
        // If conversion fails, keep as JSON
        outputData = results;
      }
    }

    return [{ json: {
      status: 'success',
      action: 'scrape',
      data: outputData,
      rawHtmlLength: rawHtml.length,
      selectorsUsed: Object.keys(selectors),
      scrapeType,
      metadata: {
        ...metadata,
        scrapedAt: new Date().toISOString(),
        url: targetUrl,
        statusCode: 200,
        contentType: response.headers['content-type'] || 'unknown'
      }
    } }];

  } else if (action === 'fill_form' || action === 'submit_form') {
    // Form filling logic
    // In a real implementation, this would use Puppeteer/Playwright via a service
    // For now, we'll prepare the data for submission

    const formDataToSend = new URLSearchParams();
    Object.keys(formData).forEach(key => {
      formDataToSend.append(key, formData[key]);
    });

    // Try to submit the form
    try {
      const response = await axios.post(targetUrl, formDataToSend, {
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
          ...requestHeaders
        }
      });

      return [{ json: {
        status: 'success',
        action: 'submit_form',
        data: {
          message: 'Form submitted successfully',
          responseStatus: response.status,
          submittedData: formData
        },
        metadata: {
          ...metadata,
          submittedAt: new Date().toISOString(),
          url: targetUrl,
          statusCode: response.status
        }
      } }];
    } catch (submitError) {
      // If submission fails, still return the prepared data
      return [{ json: {
        status: 'form_prepared',
        action: 'prepare_form',
        data: {
          message: 'Form data prepared but submission failed',
          error: submitError.message,
          preparedData: formData
        },
        metadata: {
          ...metadata,
          preparedAt: new Date().toISOString(),
          url: targetUrl
        }
      } }];
    }
  }
} catch (error) {
  // Handle errors
  return [{ json: {
    status: 'error',
    action: action || 'unknown',
    error: error.message,
    metadata: {
      ...metadata,
      attemptedAt: new Date().toISOString(),
      url: targetUrl
    }
  } }];
}
